import sys

def binary_search(arr, k):
    left, right = 0, len(arr) - 1
    while left <= right:
        middle = (left + right) // 2
        if arr[middle] == k:
            return middle
        elif arr[middle] > k:
            right = middle - 1
        else:
            left = middle + 1
    return -1

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        k = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        out.append(str(binary_search(arr, k)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

